const settings = $('Load App Settings').first()?.json ?? {};
const request = $('Team Management App Webhook').first()?.json ?? $input.first()?.json ?? {};
const query = request.query ?? request;
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const parseOptionalBool = (value) => {
  const normalized = clean(value).toLowerCase();
  if (!normalized) return null;
  if (['1', 'true', 'yes', 'y', 'on'].includes(normalized)) return true;
  if (['0', 'false', 'no', 'n', 'off'].includes(normalized)) return false;
  return null;
};
const parseId = (value) => {
  const n = Number.parseInt(clean(value), 10);
  return Number.isInteger(n) && n > 0 ? n : null;
};
const deriveBaseUrl = (sourceHeaders, fallback) => {
  const forwardedProto = clean(sourceHeaders['x-forwarded-proto']);
  const forwardedHost = clean(sourceHeaders['x-forwarded-host']);
  const host = forwardedHost || clean(sourceHeaders.host);
  const forwardedPort = clean(sourceHeaders['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefault = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefault) authority = authority + ':' + forwardedPort;
  }
  return proto + '://' + authority;
};
const normalizeCategory = (value) => {
  const raw = clean(value);
  return ['ALL', 'Mens', 'Ladies', 'Mixed', 'Vets'].includes(raw) ? raw : 'ALL';
};
const normalizeAttachmentMode = (value) => {
  const normalized = clean(value).toLowerCase().replace(/_/g, '-');
  const aliases = {
    '1': 'own-plus-reserves',
    '2': 'own-next-plus-reserves',
    '3': 'all-in-section',
    'own-plus-reserves': 'own-plus-reserves',
    'ownplusreserves': 'own-plus-reserves',
    'own+reserves': 'own-plus-reserves',
    'own-reserves': 'own-plus-reserves',
    'own-next-plus-reserves': 'own-next-plus-reserves',
    'ownnextplusreserves': 'own-next-plus-reserves',
    'own+next+reserves': 'own-next-plus-reserves',
    'own-next-reserves': 'own-next-plus-reserves',
    'ownnextreserves': 'own-next-plus-reserves',
    'own-next': 'own-next-plus-reserves',
    'current': 'own-next-plus-reserves',
    'all-in-section': 'all-in-section',
    'allinsection': 'all-in-section',
    'all': 'all-in-section',
  };
  return aliases[normalized] || 'all-in-section';
};
const normalizeDeliveryMode = (value) => clean(value).toLowerCase() === 'production' ? 'production' : 'test';
const validViews = new Set(['teams', 'players', 'mailout', 'nicknames', 'overrides']);
const rawView = clean(query.view).toLowerCase();
const view = validViews.has(rawView) ? rawView : 'teams';
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
return [{
  json: {
    view,
    team_id: parseId(query.team_id),
    edit_team_id: parseId(query.edit_team_id),
    edit_player_id: parseId(query.edit_player_id),
    edit_nickname_id: parseId(query.edit_nickname_id),
    edit_override_id: parseId(query.edit_override_id),
    season: clean(query.season),
    category: normalizeCategory(query.category),
    attachment_mode: normalizeAttachmentMode(query.attachment_mode || query.attachmentMode || query.scope),
    delivery_mode: normalizeDeliveryMode(query.delivery_mode || query.deliveryMode || query.mode || settings.email_delivery_mode),
    test_recipient: clean(query.test_recipient || query.testRecipient) || clean(settings.email_test_recipient) || 'steve.short@gmail.com',
    include_shared_bcc_in_test: parseOptionalBool(query.include_shared_bcc_in_test || query.includeSharedBccInTest) !== false,
    lookup_q: clean(query.lookup_q),
    flash_message: clean(query.message),
    flash_error: clean(query.error),
    n8n_base_url: n8nBaseUrl,
  },
}];
